```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return -1; // Transaction begin failed
  }

  // 3. Delete users with last_login before 2025-01-01
  auto delete_result = (sqlgen::delete_from<User> | 
                       where("last_login"_c < "2025-01-01"))(conn);
  if (!delete_result) {
    // Rollback would be needed here in production, but per spec we just return error
    return -1; // Delete operation failed
  }

  // 4. Commit the transaction
  auto commit_result = sqlgen::commit(conn);
  if (!commit_result) {
    return -1; // Commit failed
  }

  // 5. Return the result of the commit operation
  return commit_result ? 0 : -1; // 0 for success, -1 for failure
}

} // namespace delete_inactive_users
