#include <gtest/gtest.h>
#include <vector>
#include <string>

#include "query_daily_traffic_metrics.hpp"

namespace query_daily_traffic_metrics {

/**
 * Test Case: Test daily traffic metrics query
 * 
 * Test Scenario:
 * - Create PageVisit table
 * - Insert sample visits across multiple days
 * - Call query_daily_traffic_metrics
 * - Verify correct grouping by date and counts
 */
TEST(sqlite, query_daily_traffic_metrics) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<PageVisit>(conn);
  exec(conn, "DROP VIEW IF EXISTS DailyTrafficView;");

  // 1. Create table and insert data
  create_table<PageVisit>(conn);

  std::vector<PageVisit> visits = {
      {1, "home", "2023-10-01 10:00:00"},
      {2, "about", "2023-10-01 11:00:00"},
      {3, "home", "2023-10-01 12:00:00"}, // Duplicate URL same day

      {4, "products", "2023-10-02 09:00:00"},
      {5, "products", "2023-10-02 09:30:00"}, // Duplicate URL same day

      {6, "contact", "2023-10-03 15:00:00"}
  };
  insert(conn, visits);

  // 2. Call query function
  auto metrics = query_daily_traffic_metrics();

  // 3. Verify results
  // Expected:
  // 2023-10-01: 3 visits, 2 unique (home, about)
  // 2023-10-02: 2 visits, 1 unique (products)
  // 2023-10-03: 1 visit, 1 unique (contact)

  ASSERT_EQ(metrics.size(), 3);

  EXPECT_EQ(metrics[0].visit_date, "2023-10-01");
  EXPECT_EQ(metrics[0].total_visits, 3);
  EXPECT_EQ(metrics[0].unique_pages, 2);

  EXPECT_EQ(metrics[1].visit_date, "2023-10-02");
  EXPECT_EQ(metrics[1].total_visits, 2);
  EXPECT_EQ(metrics[1].unique_pages, 1);

  EXPECT_EQ(metrics[2].visit_date, "2023-10-03");
  EXPECT_EQ(metrics[2].total_visits, 1);
  EXPECT_EQ(metrics[2].unique_pages, 1);
}

}  // namespace query_daily_traffic_metrics

