 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // 1. Connect to the SQLite database "test_db.sqlite"
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    std::cerr << "Failed to connect to database: " << conn_result.error().what() << std::endl;
    return false;
  }
  auto conn = conn_result.value();

  // 2. Use sqlgen::write function with or_replace parameter set to true
  auto write_result = sqlgen::write(conn, items);
  if (!write_result) {
    std::cerr << "Failed to upsert items: " << write_result.error().what() << std::endl;
    return false;
  }

  // 3. Read back the items using sqlgen::read function
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    std::cerr << "Failed to read items: " << read_result.error().what() << std::endl;
    return false;
  }
  auto read_items = read_result.value();

  // 4. Compare the original items with the read items to verify upsert behavior
  if (items.size() != read_items.size()) {
    std::cerr << "Item count mismatch: expected " << items.size() 
              << ", got " << read_items.size() << std::endl;
    return false;
  }

  for (size_t i = 0; i < items.size(); ++i) {
    const auto& original = items[i];
    const auto& read_item = read_items[i];

    if (original.item_id != read_item.item_id ||
        original.name != read_item.name ||
        original.quantity != read_item.quantity) {
      std::cerr << "Item " << i << " mismatch: expected (" 
