                << original.quantity << "), got (" 
                << read_item.item_id << ", " << read_item.name << ", " 
                << read_item.quantity << ")" << std::endl;
      return false;
    }
  }

  std::cout << "Upsert operation completed successfully. Verified " 
            << items.size() << " items." << std::endl;
  return true;
}

