 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect()
      .and_then(drop<User> | if_exists)
      .and_then(drop<Friendship> | if_exists)
      .and_then(create_table<User>)
      .and_then(create_table<Friendship>)
      .and_then(insert(users))
      .and_then(insert(friendships))
      .value();

  // Find all pairs of friends
  const auto query = (select_from<Friendship, "f">(
          col<"username", "u1">.as<"user1_name">(), 
          col<"username", "u2">.as<"user2_name">()) |
      inner_join<User, "u1">(col<"user1_id", "f"> == col<"user_id", "u1">) |
      inner_join<User, "u2">(col<"user2_id", "f"> == col<"user_id", "u2">) |
      to<std::vector<FriendConnection>>)(conn);

  return query.value();
}

}  // namespace analyze_social_network

