  if (!read_result) {
    throw std::runtime_error("Failed to read updated notes");
  }
  auto updated_notes_vec = read_result.value();

  // 5. Convert the results to the required format
  std::vector<UpdatedNote> result;
  result.reserve(updated_notes_vec.size());

